(window.courseContentFiles = window.courseContentFiles || {})["000003/0013"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>1</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0; \n    }\n    ul, ol { \n      margin: 0.2em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n    }\n    .audio-link-icon {\n      width: 28px;\n      height: 28px;\n      border: 1px solid #588157;\n      border-radius: 999px;\n      background: #f0f7f0;\n      color: #2f5d50;\n      cursor: pointer;\n      font-size: 14px;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 auto;\n    }\n    .audio-link-inline audio {\n      position: absolute;\n      width: 1px;\n      height: 1px;\n      opacity: 0;\n      overflow: hidden;\n      pointer-events: none;\n    }\n    .audio-link-icon img {\n      width: 14px;\n      height: 14px;\n      object-fit: contain;\n      pointer-events: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote></blockquote><h1 style=\"text-align: center\">Тема 102. Нарушения на ранната бременност – аборт, ектопична бременност.</h1><h2>Аборт (Abortus)</h2><p><strong>Синоним:</strong> Помятане.</p><h3>Определение и класификация</h3><p>Абортът е прекъсване на бременността преди изтичане на <strong>28-а гестационна седмица (г.с.)</strong>. След този срок прекъсването се дефинира като <i>преждевременно раждане</i>.</p><ul><li><strong>Ранни аборти:</strong> настъпват до 14-а г.с.</li><li><strong>Късни аборти:</strong> настъпват между 15-а и 28-а г.с.</li></ul><p>Основната разлика от раждането е, че при аборта плодът и плацентата се отделят и изхвърлят <strong>едновременно</strong>, независимо дали са увредени или запазени. Около 15% от бременностите завършват със спонтанен аборт.</p><h3>Етиология</h3><p>Разнообразните причини за аборт се свеждат до две основни групи:</p><ul><li><strong>Причини от страна на майката:</strong> Най-често са остри или хронични инфекциозни заболявания, ендокринни заболявания, сърдечносъдови, бъбречни и особено заболявания на матката (аномалии, ендометрити и др.), аднексите и болестните промени в таза и тазовите органи.</li><li><strong>Причини от страна на плода:</strong> Те са най-често генетични.</li></ul><h3>Патогенеза</h3><p>Механизмът на настъпване на аборта включва следните фактори:</p><ul><li><strong>Пречки при закрепването:</strong> Болестни състояния, които пречат на закрепването на оплодената яйцеклетка (плацентити, ендометрити).</li><li><strong>Затруднен растеж:</strong> Хипоплазия на матката, системни общи заболявания на майката (напр. сърдечно-съдови).</li><li><strong>Механични деформации:</strong> Деформация на матката от туморни или други обемни процеси в матката или таза (кисти, доброкачествени и злокачествени тумори, сраствания и др.).</li><li><strong>Селективен механизъм:</strong> Допуска се възможността за наличие на механизъм, при който дефектните яйца се елиминират естествено.</li></ul><h3>Патоморфологични промени</h3><ul><li><strong>Макроскопия:</strong> При медицински аборт тъканите са раздробени и смесени с кръв. При спонтанен аборт е важно плодът да се огледа за видими малформации.</li><li><strong>Микроскопия:</strong> В децидуата (лигавицата на бременната матка) се наблюдават тромбози, огнищни некрози и левкоцитарни инфилтрати. Хориалните въси често са оточни (хидропични) и с редуцирани кръвоносни съдове.</li></ul><h3>Усложнения</h3><p>Най-опасното усложнение е последващата инфекция (<strong>септичен аборт</strong>), особено при криминални аборти. Това може да доведе до сепсис, ДИК синдром и масивни кръвозагуби. При инструментална намеса съществува риск от перфорация на матката.</p><h3>Изход</h3><p>При неусложнени случаи изходът е благоприятен. Не бива да се забравя, че честите аборти водят до хронични ендометрити, а те сами по себе си пречат на нормалното закрепване на яйцето и износване на бременността.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Извънматочна бременност (Graviditas extrauterina)</h2><p>Извънматочната бременност (ИБ) се дефинира като имплантиране на оплодената яйцеклетка на всяко друго място извън обичайната утеринна (маточна) локализация.</p><ul><li><strong>Честота:</strong> Среща се приблизително на всеки 150 нормални бременности. В 90% от случаите се касае за тубарна ИБ.</li><li><strong>Етиология:</strong> Дължи се на затруднения в придвижването и/или имплантирането на оплодената яйцеклетка. Най-честите причини са хронични възпалителни промени във вътрешните полови органи и свързаните с тях сраствания.</li></ul><h2>1. Тубарна извънматочна бременност</h2><p>Това е най-честата форма на извънматочна бременност.</p><h4>Макроскопски форми</h4><ol><li><strong>Едностранна тубарна бременност:</strong></li><ul><li><strong>Ампуларна:</strong> Най-честата локализация.</li><li><strong>Истмична (интерстициална):</strong> По-рядко срещана, в областта на истмуса.</li></ul><li><strong>Двустранна тубарна бременност:</strong> Представлява казуистична рядкост.</li></ol><h3>Морфогенеза</h3><ul><li><strong>Развитие:</strong> Има относително най-добри условия за начално развитие до 24-а г.с.</li><li><strong>Инвазия:</strong> Хорионната обвивка прониква не само в съдовете на лигавицата, но и в мускулния слой или дори до серозата на тръбата.</li><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/EyY7UMw4pgBDfiSEvRcGzGA9v9krKMOJKUVvfu3WlKVNng3DbEE5KNXqsHdq_eMsHRb4IjCkE7cI6b6CTDyZ0J32lYBiU2T68rffrZRVVsAfbf_qeYcjIKY2mv4qoFCNPeSIwjOQqe0X9j3BpfCsPRYIicbJJRy0JZUAQPPK15Xj_hRuEBzm40xDzpitB_mF?purpose=fullsize &quot;width=80%&quot;)\" id=\"note-1775397421560-5\">Реакция на Arias-Stella</span>:</strong> В стромата на маточната лигавица възниква децидуална реакция с <strong>хиперсекреторни</strong> <strong>промени </strong>в жлезите (вакуолизация на цитоплазмата, пикнотични ядра). Наличието ѝ в кюретажен материал при млади жени с аменорея и липса на хорионни въси е важен диагностичен белег.</li></ul><h4>Клиника и морфологична находка</h4><ul><li><strong>Клиника:</strong> Прояви на \"остър корем\" поради перитонеално дразнене. При голям кръвоизлив може да се развие хеморагичен шок.</li><li><strong>Макроскопия:</strong> При ранен аборт с кръвоизлив може да не се открият части от яйцето. При по-напреднала бременност сред съсиреците се откриват плодът и плодните обвивки.</li><li><strong>Микроскопия:</strong> Характерни са децидуални промени в лигавицата и хорионни въси, проникващи на различна дълбочина в стената на маточната тръба.</li></ul><h4>Усложнения</h4><ul><li><strong><span class=\"editor-note\" data-note=\"![Image](https://images.openai.com/static-rsc-4/SSd7aHB26vpEkwecwPjnnbeJC3k91yXzHKhCVsxf-SNnvHQ9WRwi5GDGCSUFWZ3GUZsDb1yKeV9CI5PZInhuljuK41dm5yVoEisjEqDnXIfNHQTMZqtfvxohU4oyhhZrOLZ4o5606I-gRXDawTz0OkkzmyNE5bWxURWZdsRKwSQr3acxqGPqx4H-r4Vx02bN?purpose=fullsize &quot;width=100%&quot;)\" id=\"note-1775397471761-6\">Хемосалпинкс</span>:</strong> Разкъсване на големи съдове и масивен кръвоизлив в тръбата, често съпроводен с тубарен аборт (изхвърляне на плода в коремната кухина).</li><li><strong>Руптура на маточната тръба:</strong> Разкъсване на стената с кръвоизлив, събиращ се обикновено в Дъгласовото пространство.</li><li><strong>Промени в плода:</strong> При смърт в коремната кухина плодът може да се калцифицира (<strong>Lithopaedion</strong>) или да се мумифицира (<strong>Faetus papiraceus</strong>).</li><li><strong>Вторична абдоминална бременност:</strong> Повторно имплантиране на жизнеспособното яйце в коремната кухина след разкъсване на тръбата.</li></ul><h3>2. Други локализации</h3><h4>Яйчникова бременност</h4><p>Ранно оплождане и внедряване на яйцето директно в яйчника. Обикновено завършва с руптура и кръвотечение през 8-а до 12-а г.с.</p><h4>Абдоминална (перитонеална) бременност</h4><p>Много рядка форма. Оплоденото яйце се внедрява в мезентериума. Описани са редки случаи на доносване, но най-често се усложнява с обилно кръвотечение и шок.</p><h4>Цервикална бременност</h4><p>Имплантация в шийката на матката. Рядка локализация, която често завършва с ранен аборт и масивни кръвоизливи поради разкъсване на цервикалните съдове от трофобласта.</p><h3>Диагноза и изход</h3><p>За диагнозата помага изследването на <strong>хорионгонадотропин (HCG)</strong> и <strong>ултразвуковата находка</strong>. Хистологичното изследване на ендометриума показва дисонанс: изразена децидуална реакция (<strong>Arias-Stella</strong>) при липса на хорионни въси в матката. Състоянието изисква спешна хирургична намеса.</p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Тема 103. Нарушения на късната бременност. Възпалителни процеси на плацентата и околоплодните обвивки. Плакопатии.</h1><h1>Нарушение на плацентарното кръвообращение (Плакопатии)</h1><p>Към тази група се отнасят хематомите, интервилозните тромбози и инфарктите на плацентата.</p><h2>Хематоми на плацентата</h2><p>Най-често се срещат при <strong>еклампсия</strong>. Дължат се на разкъсване на предварително увредена стена на спирална маточна артерия или на отлепване на плацентата.</p><h3>Локализация</h3><p>Според разположението си биват:</p><ul><li><strong>Маргинални:</strong> По-масивни, клинично се проявяват с кървене.</li><li><strong>Централни:</strong> Не се проявяват с кървене, но могат да имат фатални последици за плода (масивна аспирация, остра антепартална асфиксия и смърт).</li><li><strong>Базални:</strong> Дължат се на преждевременно отлепване на плацентата (<em>Ablatio placentae</em>).</li><li><strong>Субхориални:</strong> Обикновено малки, не се манифестират клинично.</li></ul><p><strong>Макроскопия:</strong> Видът им зависи от тяхната давност и не се отличава от хематомите в други органи. За майката е от значение размерът на кръвозагубата.</p><h2>Инфаркт на плацентата</h2><p>Среща се най-често при <strong>еклампсия</strong>, но може да се наблюдава и при нормална бременност.</p><h3>Морфогенеза</h3><p>Инфарктите са <strong>анемични</strong>. Дължат се на остро прекъсване на кръвния ток в спиралните артерии в резултат на тромбоза. Обхващат един или повече лобули.</p><h3>Макроскопия</h3><ul><li><strong>Пресни инфаркти:</strong> Тъмночервени, плътни, обхващат цялата дебелина на плацентата (диаметър до 2-3 cm).</li><li><strong>Стари инфаркти:</strong> Леко хлътнали, със сивкаво-белезникав цвят и повишена плътност.</li></ul><h3>Микроскопия</h3><ul><li><strong>Исхемична фаза:</strong> Интервилозното пространство е силно стеснено, тъй като вилите са притиснати плътно една до друга.</li><li><strong>Късна фаза:</strong> Настъпва <strong>коагулационна некроза </strong>на стромата и десквамация на епитела. Виждат се само <strong>„сенки“ от вили</strong> (структурна некроза).</li></ul><h3>Диференциална диагноза на инфаркта</h3><p>Истинските инфаркти трябва да се различават от <strong>фибриноидните депа</strong> (т.нар. фибриноидни „инфаркти“):</p><ul><li><strong>Макроскопия:</strong> И двете състояния си приличат по белезникавия цвят и плътната консистенция.</li><li><strong>Микроскопия:</strong> При фибриноида се виждат фиброзно променени въси без трофобласт, обградени от фибриноид, но <strong>липсва некроза</strong>.</li><li><strong>Патологично значение:</strong> За разлика от истинския инфаркт, фибриноидните депа нямат патологично значение. Те се приемат за дегенеративен процес, близък до апоптозата.</li></ul><h2>Тромбоза на интервилозното пространство</h2><ul><li>Среща се сравнително рядко.</li><li><strong>Патологично значение:</strong> Недоказано.</li><li><strong>Морфология:</strong> Макроскопски и микроскопски картината съответства на тази на <strong>смесен тромб</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Възпалителни изменения в плацентата (Placentitis)</h2><p>Възпалителните процеси в плацентата се означават като <strong>плацентит</strong>. Те имат решаващо значение за изхода на бременността и здравето на плода, като често протичат безсимптомно за майката.</p><h3>Механизми на заразяване</h3><p>Съществуват два основни пътя за проникване на инфекцията:</p><ol><li><strong>Асцендентен път:</strong> Инфектиране от влагалището и цервикалния канал (най-чест). Предразполагащ фактор е изтичането на околоплодните води, но е възможно и при интактен околоплоден сак.</li><li><strong>Хематогенен път:</strong> Инфектиране чрез кръвта на майката.</li></ol><h3>Асцендентна форма</h3><p>Това е най-честата форма, при която обикновено се засягат околоплодните обвивки — <strong>хориоамнионит (chorioamnionitis)</strong>. При разпространение по съседство се развива базален или децидуален плацентит.</p><ul><li><strong>Етиология:</strong> Причинява се от нормалната флора на влагалището (E. coli, стрептококи, стафилококи, хламидии и др.).</li><li><strong>Макроскопия:</strong> Характеризира се с помътняване на околоплодната течност или нейното нагнояване.</li><li><strong>Микроскопия:</strong> Хориоамнионът е дифузно или огнищно пропит с полинуклеарни левкоцити, понякога до степен на абсцедиране. Аналогични промени се наблюдават в базалната пластинка, децидуата и пъпната връв (<p>Funiculitis)</p>.&nbsp;<p>Типично е засягането на пъпните съдове от гноен васкулит, </p><p>което крие риск от пренасяне на инфекцията върху плода.</p></li></ul><h3>Хематогенна форма</h3><p>Характерно за тази форма е първичното засягане на плацентарните въси — <strong>вилит (villitis)</strong>.</p><ul><li><strong>Макроскопия:</strong> Промените са неспецифични и огнищни; по-рядко се ангажират базалната пластинка и децидуата.</li><li><strong>Микроскопия:</strong> Наблюдават се инфектирани инфаркти, абсцеси (при гноеродни причинители) или кръглоклетъчни инфилтрати (при вирусни инфекции). <br>Съществуват специфични находки според причинителя:</li><ul><li><strong>Листериоза:</strong> Характерни грануломи с некротични въси, пропити с фибрин и обградени от възпалителен вал.</li><li><strong>Луес (Сифилис):</strong> Увеличена плацента с хидропични въси, ендартерит и периваскуларни инфилтрати в стромата на въсите.</li><li><strong>Токсоплазмоза:</strong> Вилозен плацентит с периваскуларни инфилтрати от лимфоцити и плазмоцити.</li></ul><li><strong>Клинично значение:&nbsp;</strong>Повечето промени са безсимптомни за майката, но са водеща причина за патологичен изход на бременността и тежки перинатални инфекции у плода и новороденото.</li></ul><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><br></p><p><br></p><hr data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\" contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1 style=\"text-align: center\">Тема 104. Токсемия на бременността. Интраутеринна растежна рестрикция.</h1><h1>Токсикози на бременността</h1><p><strong>Синоними:</strong> Токсемия на бременността, ЕРН-гестози, прееклампсия и еклампсия, късни токсикози.</p><p>Заболяването се развива в <strong>последния триместър</strong> на бременността. Характеризира се с триада: <strong>отоци, протеинурия и хипертония</strong> — състояние, известно като <strong>прееклампсия</strong>. При добавяне на гърчове и кома състоянието преминава в <strong>еклампсия</strong>.</p><ul><li><strong>Честота:</strong> 5-10% от бременните, по-често при възрастни първескини. </li><li><strong>Рискови фактори:</strong> Наднормено тегло, нисък социален статус, стрес. Развива се обикновено след 24 г.с. (най-често 30-36 г.с.).</li><li><strong>Етиология:</strong> Неясна (допускат се имунни или генетични причини).</li></ul><h3>Патогенеза</h3><p>Основните моменти в развитието на заболяването са:</p><ol><li><strong>Хипертензия и вазоспазъм:</strong> Намален синтез на простагландин Е и повишен ренин водят до генерализиран вазоспазъм и повишена чувствителност към ангиотензин.</li><li><strong>Плацентарна хипоперфузия:</strong> Вазоспазмът води до хипоксия в плацентата, повишена съдова пропускливост и <strong>фибриноидна некроза</strong> на утеро-плацентарните съдове.</li><li><strong>ДИК синдром:</strong> Плацентарната исхемия освобождава голямо количество тромбопластин, което води до образуване на фибринни тромби в микроциркулацията на таргетните органи - <p>черен дроб, бъбреци, мозък, </p><p>хипофиза и др.</p></li></ol><h3>Морфологични промени в органите</h3><h4>Черен дроб</h4><ul><li><strong>Макроскопия:</strong> Увеличен, изпъстрен с различни по форма и големина кръвоизливи.</li><li><strong>Микроскопия:</strong> Фибринни тромби в перипорталните съдове, огнищни <strong>кръвоизливи</strong>, стеатоза и некроза на хепатоцитите (периферно в делчетата).</li></ul><h4>Бъбреци</h4><ul><li><strong>Макроскопия:</strong> Варират от непроменени до леко увеличени. При смърт – картина на <strong>„голям бял бъбрек“</strong> или симетрични кортикални некрози.</li><li><strong>Микроскопия:</strong> Фибринни тромби в гломерулните капиляри, микроинфаркти и микрокръвоизливи.</li><li><strong>Електронна микроскопия:</strong> Дифузно набъбване на ендотела, отлагане на фибрин под базалната мембрана и мезенгиална пролиферация.</li></ul><h4>Мозък</h4><ul><li><p><strong>Макроскопия:</strong> Оточен, хиперемиран, с точковидни кръвоизливи.</p></li><li><p><strong>Микроскопия</strong>: О</p><p>ткриват се фибринни тромби. Понякога се засяга и аденохипофизата, в която настъпват кръвоизливи и некрози.</p></li><li><strong>Други органи:</strong> Подобни промени — микротромби, кръвоизливи и некрози.</li></ul><h4>Плацента</h4><ul><li><strong>Макроскопия:</strong> Диапазон от типеремия, кръвоизливи и инфаркти.</li><li><strong>Микроскопия:</strong> Наблюдава се <strong>фибриноидна некроза </strong>в медията на съдовете и субендотелно натрупване на <strong>пенести макрофаги </strong>(остра атероза). Установяват се тромбози и свързаните с тях кръвоизливи и инфаркти. Като израз на вилозна исхемия се наблюдава усилено зониране на синцитиалния слой под форма на така наречените <strong>синцитиални </strong><strong>пъпки</strong>.</li></ul><h3>Изход и прогноза</h3><p>Зависи от два фактора: степен на съдовите и органните промени и продължителност на процеса. Заболяването е еднакво неблагоприятно за плода и майката</p><p><strong>За плода:</strong></p><ul><li>Вътреутробна хипотрофия (растежна рестрикция) или антинатална смърт.</li><li>Смъртността при новородените е 3 пъти по-висока от средната.</li></ul><p><strong>За майката:</strong></p><ul><li>Леките случаи завършват благополучно (симптомите изчезват за 1-2 седмици).</li><li>Тежките случаи могат да оставят трайни увреждания като цироза и хронична бъбречна недостатъчност, а в редки случаи завършват със смърт.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3><strong>Интраутеринна растежна рестрикция</strong></h3><p><strong>Определение:</strong> Състояние, при което фетусът не успява да достигне своя генетично заложен потенциал за растеж в матката. Резултатът е новородено, което е <strong>малко за гестационната си възраст</strong>— т.е. то е <strong>недорасло</strong>, но не задължително незряло.</p><h4><strong>Основни етиологични групи</strong></h4><ul><li><strong>Фетални фактори (Симетричен тип):</strong></li><ul><li><strong>Механизъм:</strong> Намаляват самия потенциал за растеж на плода. Отокът и забавянето засягат еднакво всички органи.</li><li><strong>Причини:</strong> Хромозомни нарушения (откриват се при 17% от случаите), вродени малформации и инфекции от <strong>TORCH групата</strong>.</li></ul><li><strong>Плацентарни фактори (Асиметричен тип):</strong></li><ul><li><strong>Механизъм:</strong> Компрометират маточно-плацентарното кръвоснабдяване. <strong>Мозъкът е пощаден</strong> за сметка на висцерални органи като черния дроб.</li><li><strong>Причини:</strong> Предлежание на плацентата (<em>placenta praevia</em>), отлепване (<em>abruptio placentae</em>), инфаркти или структурни аномалии (двудялова плацента, <em>pl. circumvallate</em>).</li></ul><li><strong>Майчини фактори (Най-чести):</strong></li><ul><li><strong>Съдови заболявания:</strong> Прееклампсия и хронична хипертония.</li><li><strong>Тромбофилии:</strong> Наследствена или придобита хиперкоагулация.</li><li><strong>Външни влияния:</strong> Тежко тютюнопушене (директно води до ниско тегло), алкохол, наркотици и недохранване (хипогликемия).</li><li><strong>Лекарства:</strong> Тератогени като антиконвулсанта <strong>фенитоин</strong>.</li></ul></ul><h4><strong>Дългосрочни последици</strong></h4><p>Бебетата с ограничен растеж често носят дефицити през целия живот, включително:</p><ul><li>Мозъчна дисфункция и затруднения в ученето.</li><li>Сензорни (зрителни и слухови) увреждания.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 105: Родова инфекция. Сепсис.</h1><h2>Следродова инфекция и родов сепсис</h2><p>Възпалителните промени, които се развиват в матката след раждане или аборт, се означават като <strong>следродова инфекция</strong>.</p><ul><li><strong>Честота:</strong> Днес заболеваемостта е рязко снижена поради антибиотиците. Голямо значение има инфекцията след криминални аборти.</li><li><strong>Етиология:</strong> Причинява се от Грам (-) чревни бактерии, стрептококи, стафилококи, анаероби и др.</li><li><strong>Патогенеза:</strong> Инфектира се раневата повърхност на матката (мястото на плацентата). Фактори са задържането на части от плацентата или децидуата.</li><ul><li><strong>Екзоинфекция:</strong> Чрез замърсени инструменти или ръкавици.</li><li><strong>Автоинфекция:</strong> Чрез флората на влагалището и лохиите. По-чест вариант.</li></ul><li><p><strong>Патоморфология: </strong>Различават се две форми на</p><p>следродовата инфекция, които имат редица особености в морфологията и протичането - септична и гнилостна форма.</p><br></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Септична форма</h3><p>Започва като ендометрит (Endometritis septica).</p><h3>Морфология</h3><ul><li><strong>Макроскопски</strong>:&nbsp;<p>Вътрешната повърхност на матката е покрита с неравен, мръсносивкав или жълтеникаво-зеленикав <strong>налеп</strong>. Той е най-обилен в раневата област и трудно се снема.</p></li><li><strong>Микроскопия:</strong> Наблюдава се <strong>фибринозно-гнойна инфилтрация</strong>, обхващаща лигавицата и вътрешната част на мускулния слой. Откриват се обширни <strong>некротични полета</strong>. Венозните и лимфните съдове са с прояви на <strong>гноен тромбофлебит </strong>и <strong>гноен лимфангит</strong>, които спомагат за разпространение на процеса в дълбочина и образуване на <strong>абсцеси</strong>.</li></ul><h4>Усложнения</h4><ul><li>Флегмонозен метрит и параметрит;</li><li>Перитонит;</li><li>Септикопиемия.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Гнилостна форма</h3><p>Започва като гнилостен ендометрит (<strong>Endometritis putrida</strong>) при разпад на остатъци от плацента и обвивки.</p><h4>Морфология</h4><ul><li><strong>Макроскопия:</strong> Раневата повърхност е рехава, къслива, мръснозеленикава със силна гнилостна миризма.</li><li><strong>Микроскопия:</strong> Гнилостно възпаление с обширни некрози и тромбофлебит. При наличие на <strong>газотделящи микроорганизми </strong>се наблюдава <strong>интерстициален емфизем </strong>(газови мехурчета в тъканта) - <strong>емфизематозен миометрит</strong>.</li></ul><h4>Усложнения и Изход</h4><ul><li>Процесът обикновено е локализиран, но масивната резорбция на токсини води до <strong>сепсис</strong> и тежък <strong>ендотоксичен шок</strong>.</li><li>Въпреки антибиотиците, и двете форми могат да завършат със смърт.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 106. Заболявания на трофобласта – видове.</h1><p>Тази група включва тумори и тумороподобни състояния, произлизащи от хорионния епител. Те се развиват след бременност (нормална или патологична), аборт или гроздовидна мола.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Гроздовидна бременност (Mola hydatidosa)</h2><p>Това е патологичен процес, при който хорионните въси се променят структурно – стромата им набъбва оточно, а епителът им пролиферира в различна степен. Смята се за <strong>факултативна преканцероза</strong> на хорионкарцинома.</p><p><strong>Клинична картина\n</strong>Най-често се проявява с гестационно кървене, понякога с отделяне на мехурчета. Характерно е, че матката често нараства по-бързо, отколкото съответства на срока на бременността.</p><p><strong>Макроскопски находки\n</strong>Матката е изпълнена с голям брой прозрачни, тънкостенни мехурчета, съдържащи бистра течност. Те са свързани помежду си и наподобяват <strong>гроздови зърна</strong>. При пълната (комплетна) форма плод и обвивки липсват, докато при частичната могат да се открият атрофични части от ембрион.</p><p><strong>Микроскопски находки\n</strong>Хистологично се наблюдават три водещи белега:</p><ol><li><strong>Хидропична дегенерация:</strong> Силно оточна строма на хорионните въси.</li><li><strong>Аваскуларизация:</strong> Липса или значително намаляване на кръвоносните съдове във въсите.</li><li><strong>Епителна пролиферация:</strong> Разрастване на трофобластния слой (цито- и синцитиотрофобласт).</li></ol><p><strong>Форми според цитогенетиката:</strong></p><ul><li><strong>Комплетна мола:</strong> Дифузна хиперплазия на епитела и диплоиден кариотип (46 XX). Рискът от прерастване в хорионкарцином тук е най-висок.</li><li><strong>Частична мола:</strong> Оточността и хиперплазията са огнищни; кариотипът е триплоиден (69 XXY).</li></ul><p><strong>Диагноза\n</strong>Основен метод за диагностика и контрол е проследяването на <strong>β-HCG</strong> (човешки хорионгонадотропин). Персистиращо високо ниво след кюретаж насочва към злокачествен процес</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Деструираща мола (Mola destruens)</h2><p>Известна е още като <strong>инвазивна мола</strong>. Тя представлява по-агресивен вариант на гроздовидната бременност.</p><p><strong>Макроскопски находки\n</strong>Представлява червеникав туморен възел, който е трудно разграничим от околната мускулатура на матката. Често макроскопски се бърка с хорионкарцином.</p><p><strong>Микроскопски находки\n</strong>Основният диагностичен белег е наличието на хорионни въси (с трофобластна пролиферация и възможни оточни промени), които са <strong>инвазирали дълбоко в миометриума</strong> или дори са го перфорирали.</p><p><strong>Усложнения и изход\n</strong>При пробив на маточната стена може да настъпи фатален кръвоизлив. Възможна е и емболизация на въси в отдалечени органи (напр. бял дроб), но биологично тя остава доброкачествена и се повлиява отлично от химиотерапия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хорионкарцинома (Chorioncarcinoma)</h2><p>Злокачествен епителен тумор, произлизащ от трофобластния епител. Развива се след нормално раждане, аборт или гроздовидна мола (т.нар. гестационен тип).</p><p><strong>Клинична картина\n</strong>Характерно е наличието на <strong>неправилни кръвотечения </strong>или <strong>кафеникаво </strong>„<strong>зацапване</strong>“ месеци след прекарана на бременност, аборт или гроздовидна бременност. Често първите симптоми са от метастазите (кръвохрак или неврологична симптоматика).</p><p><strong>Макроскопски находки\n</strong>Туморът се състои от меки, червеникави възли с „гъбеста“ структура в засегнатия орган. Повърхността му е силно пъстра заради зони на прясна кръв и белезникаво-жълти некрози.</p><p><strong>Микроскопски находки</strong></p><p>Хистологично туморът се отличава с атипично разрастване на два вида клетки: <strong>цитотрофобласт </strong>(Лангерхансови клетки) и <strong>синцитиотрофобласт</strong>.</p><ul><li><strong>Лангерхансовите клетки </strong>обикновено <strong>преобладават</strong>, организирани в <strong>островчета </strong>или <strong>полета</strong>. Те са обградени или пронизани от <strong>синцитиални клетки </strong>с хиперхромни и деформирани ядра. Често двата типа клетки са смесени безпорядъчно.</li><li>Най-характерното за този тумор е <strong>пълното отсъствие на собствена строма и собствени съдове</strong>. Туморните елементи не образуват въси.</li><li>Туморните клетки растат директно сред масивни кръвоизливи и фибрин, получени от разрушените от тумора съдове на майката. В околната тъкан се наблюдават некрози и кръвни изливи</li></ul><p><strong>Метастазиране\n</strong>Инвазира кръвоносните съдове много рано. Най-честите метастази са в <strong>белия дроб</strong> и <strong>влагалището</strong>, следвани от мозък, черен дроб и бъбреци.</p><p><strong>Усложнения</strong></p><p>При агресивен и дълбок растеж туморът може да прорасне през маточната стена, достигайки до <strong>серозата </strong>и <strong>аднексите</strong>, което води до масивни кръвоизливи. В метастатичните огнища често се наблюдават:</p><ul><li>Обширни <strong>исхемични некрози</strong>.</li><li>Вторични <strong>инфекциозни усложнения</strong>.</li></ul><p><strong>Изход и прогноза</strong></p><p>При ранно диагностициране и правилно проведена химиотерапия се наблюдава <strong>пълна регресия</strong> на първичния тумор и метастазите при мнозинството от болните. Това особено се отнася за т.нар. <strong>гестационен</strong> <strong>тип </strong>на хорионкарцинома - когато той се развива след нормална бременност или аборт и гроздовидна мола.</p><p><strong>Диагноза</strong></p><p>Проследяване на <strong>β-HCG</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center; color: rgb(0, 176, 80) !important\">Въведение за новородени:</h1><h2><strong>Периоди и дефиниции</strong></h2><p>В патологията и неонатологията времевите граници са критични за определяне на състоянието:</p><ul><li><strong>Перинатален период:</strong> Обхваща времето от <strong>28-а г.с.</strong> до <strong>7-ия ден</strong> след раждането.</li><li><strong>Период на новороденото (Неонатален период):</strong> От момента на раждането до <strong>28-ия ден</strong>.</li><ul><li><strong>Ранен:</strong> 0 – 7-и ден.</li><li><strong>Късен:</strong> 7-и – 28-и ден.</li></ul><li><strong>Преносеност:</strong> Раждане след <strong>40-а г.с.</strong></li></ul><h2><strong>Класификация според гестационната възраст и теглото</strong></h2><ul><li><strong>Недоносеност и незрялост:</strong> Плод, роден <strong>преди 37-а г.с.</strong> и с тегло <strong>под 2500 гр.</strong></li><li><strong>Фетална растежна рестрикция:</strong> Доносено бебе (в термин), но с тегло <strong>под 2500 гр.</strong> (т.нар. \"недораснали\" деца). 1/3 от децата родени в термин са така.</li><li><strong>Тегло спрямо гестационната възраст:</strong></li><ul><li><strong>Ниско тегло:</strong> Свързва се често с тютюнопушене на майката.</li><li><strong>Високо тегло:</strong> Често се наблюдава при майки с диабет.</li></ul></ul><h2><strong> Степени на недоносеност (по тегло и възраст)</strong></h2><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Степен</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Телесна маса (гр.)</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Гестационна възраст (г.с.)</span></strong></td></tr><tr><td><strong>I степен</strong></td><td>2500 – 2001 гр.</td><td>под 37 г.с.</td></tr><tr><td><strong>II степен</strong></td><td>2000 – 1501 гр.</td><td>под 34 г.с.</td></tr><tr><td><strong>III степен</strong></td><td>1500 – 1001 гр.</td><td>под 32 г.с.</td></tr><tr><td><strong>IV степен</strong></td><td>1000 – 501 гр.</td><td>под 28 г.с.</td></tr></tbody></table><h2><strong>Потенциална жизнеспособност (Стандарт 2021 г.)</strong></h2><p>Това е теоретичната способност на плода да води извънутробен живот. Критериите са:</p><ul><li><strong>Критерий А:</strong> Тегло <strong>≥ 700 гр.</strong> и/или възраст <strong>≥ 25+0 г.с.</strong> (независимо дали е роден жив или мъртъв).</li><li><strong>Критерий Б:</strong> Тегло <strong>&lt; 700 гр.</strong> и/или възраст <strong>&lt; 25 г.с.</strong>, при условие че е роден жив и е преживял <strong>поне 3 денонощия</strong> (72 часа).</li></ul><h2><strong>Основни понятия в патологията</strong></h2><ul><li><strong>Концептус (Продукт на зачатието):</strong> Целият организъм от имплантацията до раждането. Включва фетуса и <strong>плодните придатъци</strong>:</li><ul><li>Пъпна връв и плацента.</li><li>Околоплодни ципи и течност.</li></ul><li><strong>Аборт:</strong> Прекъсване на бременността при тегло <strong>&lt; 700 гр.</strong> и възраст <strong>&lt; 25 г.с.</strong> (в Европа често се приема граница &lt; 500 гр. и &lt; 20 г.с.).</li><li><strong>Преждевременно раждане:</strong> Раждане <strong>преди 37-а г.с.</strong>, независимо от теглото. Не се счита за аборт, ако отговаря на критериите за жизнеспособност.</li><li><strong>Мъртвораждане:</strong> Смърт на жизнеспособен плод преди или по време на самото раждане.</li></ul><h2><strong>Анатомо-физиологични особености на новороденото</strong></h2><p>Поради своята незрялост, новороденото (особено недоносеното) проявява:</p><ol><li><strong>Незрялост</strong> на нервната и ендокринната системи.</li><li><strong>Повишена проницаемост</strong> на тъканните бариери и съдовия пермеабилитиет.</li><li><strong>Слаба имунологична реактивност</strong>, което го прави силно податливо на инфекции.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 107. Асфиксия на новороденото. Пневмопатии – аспирация, ателектаза, хиалинно-мембранна болест.</h1><h1>Асфиксия на плода</h1><p><strong>Дефиниция:</strong> Остра хипоксия на плода, възникваща в резултат на внезапно и рязко нарушение на маточно-плацентарното или фето-плацентарното кръвообращение. Тя е причина за <strong>15-20%</strong> от перинаталната смъртност.</p><h3>1. Етиология</h3><ul><li><strong>Плацентарни:</strong> Преждевременно отлепване на плацентата, <em>placenta praevia</em>, масивни инфаркти.</li><li><strong>Пъпна връв:</strong> Изпадане, опъване и притискане притискане, затегнати истински възли.</li><li><strong>Маточни:</strong> Екстремно силни контракции при тесен таз или едър плод, притискащи маточните съдове.</li></ul><h3>2. Патоморфология</h3><p>Морфологичната картина се владее от два основни белега: </p><ul><li><strong>Остър венозен застой (цианоза).</strong></li><li><strong>Хеморагична диатеза (кръвоизливи)</strong>.</li></ul><h4>Макроскопски находки</h4><ul><li><strong>Общ вид:</strong> Кожата е силно цианотична. Около ануса има <strong>мекониум</strong>, отделен поради хипоксичен стрес и отпускане на сфинктера.</li><li><strong>Сърце и кръв:</strong> Сърдечните кухини са изпълнени с <strong>тъмна, несъсирена кръв</strong>. По повърхността на сърцето (епикарда) се виждат точковидни кръвоизливи.</li><li><strong>Бели дробове:</strong> Те са безвъздушни, плътни и <strong>потъват във вода</strong>. Характерен белег е <em>интерстициалният емфизем</em> — въздушни мехурчета, подредени като броеница под плеврата. При аспирация в дихателните пътища се открива гъста слуз и мекониум.</li><li><p><strong>Коремни органи:</strong></p><br></li><ul><li><strong>Черен дроб:</strong> Силно кръвонапълнен (цианотичен). Често се наблюдава <strong>субкапсулен хематом</strong><strong>.</strong></li><li><strong>Стомашно-чревен тракт:</strong> Стените на стомаха и червата са застойни, с дребни хеморагии по лигавицата.</li></ul></ul><h4>Микроскопски находки</h4><ul><li><strong>Бели дробове:</strong></li><ul><li><strong>Фетална ателектаза</strong>, освен ако не е правена изкуствена реанимация.</li><li><strong>Артериален спазъм:</strong> Силно нагъната вътрешна еластична мембрана на артериите, което придава на лумена им <strong>звездовидна форма</strong>.</li><li>Дистрофични промени и <strong>десквамация</strong> на ендотелните клетки на съдовете.</li></ul><li><strong>Централна нервна система (ЦНС):</strong></li><ul><li><strong>Вазопареза:</strong> Паралитично разширение на съдовете и периваскуларен оток.</li><li><strong>Перивентрикулна енцефалопатия:</strong> Особено типични субепендимни кръвоизливи в зоните около мозъчните стомахчета. Тези кръвоизливи често пробиват епендима и водят до <strong>интравентрикуларен хематом</strong>.</li><li>Некротични промени в нервната тъкан (неврофагия и огнища на омекване).</li></ul><li><strong>Сърце (Миокард):</strong></li><ul><li>Наблюдава се рязко намаляване на гликогена в кардиомиоцитите (използван за енергия при анаеробни условия).</li><li>Наличие на <strong>микронекрози</strong> и дребни микрокръвоизливи в сърдечния мускул, особено под ендокарда.</li></ul><li><strong>Черен дроб:</strong></li><ul><li>Разширение на синусоидите (цианоза) и вакуолна (мастна или белтъчна) дегенерация на хепатоцитите.</li><li>Огнищни некрози на чернодробни клетки.</li></ul></ul><ul><li><strong>Ендокринни жлези:</strong></li><ul><li><strong>Надбъбреци:</strong> Масивни кръвоизливи и некрози в медулата и кората, което води до терминална надбъбречна недостатъчност.</li><li><strong>Тимус:</strong> Характерни кръвоизливи в коровата му част.</li></ul></ul><h3>3. Диагноза и Мониторинг</h3><p>Разчита се на мониториране на феталната сърдечна дейност.</p><ul><li><strong>Критичен белег:</strong> Поява на <strong>късни децелерации</strong> (забавяне на сърдечната честота в края или след пика на маточната контракция) — сигурен признак за фетална хипоксия.</li></ul><h3>4. Изход и последствия</h3><ul><li><strong>Фатален край:</strong> Анте- или интрапартална смърт.</li><li><strong>Усложнения при оцелели:</strong> Хиалинно-мембранна болест, инфекции (пневмонии), мозъчни увреждания.</li><li><strong>Дългосрочни:</strong> Трайни промени в ЦНС и изоставане в психо-физическото развитие.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Невъзпалителни пневмопатии на новороденото</h1><p>Това са група заболявания, които се характеризират с прогресираща дихателна недостатъчност в ранния неонатален период, без първичен инфекциозен процес.</p><h2>1. Хиалинно-мембранна болест (ХМБ)</h2><p>Хиалинно-мембранната болест е класически пример за <strong>дихателен дистрес синдром</strong>, обусловен от анатомична и функционална незрялост на белия дроб.</p><h4>Етиология и Рискови фактори</h4><ul><li><strong>Недоносеност:</strong> Основен фактор. Пневмоцитите тип II започват активно производство на сърфактант след 24-26 гестационна седмица, но адекватни количества се достигат едва след 34-35 седмица.</li><li><strong>Майчин диабет:</strong> Хиперинсулинемията у плода потиска синтеза на сърфактант (инсулинът е антагонист на кортизола, който стимулира белодробното узряване).</li><li><strong>Цезарово сечение (преди родова дейност):</strong> Липсва хормоналният стрес от раждането, който стимулира освобождаването на сърфактант.</li><li><strong>Асфиксия при раждането:</strong> Хипоксията и ацидозата директно увреждат пневмоцитите и инактивират вече наличния сърфактант.</li></ul><h4>Патогенетична верига</h4><p>Процесът е самозадълбочаващ се \"порочен кръг\":</p><ol><li><strong>Дефицит на сърфактант</strong> → Повишено повърхностно напрежение в алвеолите.</li><li><strong>Алвеоларен колапс (Ателектаза)</strong> → Дробът става твърд и труден за раздуване.</li><li><strong>Хиповентилация и Хипоксия</strong> → Настъпва тежка респираторна и метаболитна ацидоза.</li><li><strong>Увреждане на алвеоло-капилярната мембрана</strong> → Повишена пропускливост на капилярите.</li><li><strong>Ексудация на плазма</strong> → Богат на фибрин трансудат излиза в алвеоларното пространство.</li><li><strong>Формиране на хиалинни мембрани</strong> → Фибринът се отлага по стените, смесва се с некротичен епител и образува плътна бариера за кислорода.</li></ol><h3>Патоморфологична картина</h3><h4>Макроскопски</h4><ul><li><strong>Бели дробове:</strong> Изглеждат плътни, безвъздушни и силно кръвонапълнени (тъмночервени). </li><li><strong>Консистенция:</strong> Твърда, наподобяваща чернодробна тъкан (хепатизация).</li><li><strong>Хидростатична проба:</strong> Белият дроб <strong>потъва във вода</strong>, тъй като в него няма остатъчен въздух.</li></ul><h4>Микроскопски</h4><p>Картината се владее от специфична <strong>триада</strong>:</p><ol><li><strong>Дифузна ателектаза:</strong> Алвеолите са напълно колабирали и сбити.</li><li><strong>Разширени дуктуси:</strong> На фона на сбития дроб, алвеоларните ходове и респираторните бронхиоли са компенсаторно раздути.</li><li><strong>Хиалинни мембрани:</strong> Стените на тези раздути ходове са тапицирани с гладка, хомогенна, ярко розова (еозинофилна) материя.</li></ol><p>Картината се променя спрямо времето на преживяване:</p><ul><li><strong>Ранна фаза (първи часове):</strong> Доминира дифузна ателектаза. Алвеоларните ходове са разширени, съдържат еозинофилен трансудат (розов флуид). Хиалинните мембрани са тънки и прекъснати.</li><li><strong>Развита фаза (12-48 часа):</strong> Формират се класическите <strong>хиалинни мембрани</strong> – хомогенни, ярко розови (еозинофилни) ленти, които плътно прилепват към стените на респираторните бронхиоли и алвеоларните дуктуси.</li><li><strong>Късна фаза (след 72 часа):</strong> Ако детето преживее, мембраните започват да се фрагментират и поглъщат от макрофаги. Наблюдава се пролиферация на <strong>пневмоцити тип II</strong>, които се опитват да регенерират епитела.</li></ul><h3>Клинична динамика и усложнения</h3><ul><li><strong>\"Светъл период\":</strong> Често бебето диша нормално в първите минути, но до 2-6 часа симптомите прогресират.</li><li><strong>Симптоми:</strong> Тахипнея (&gt;60 вдишвания/мин), тираж (хлътване на междуребрията), цианоза и специфично \"стенене\" при издишване (опит на бебето да създаде налягане, което да задържи алвеолите отворени).</li></ul><p><strong>Опасни усложнения:</strong></p><ol><li><strong>Пневмоторакс:</strong> Въздухът може да пробие увредената тъкан при апаратна вентилация.</li><li><strong>Интракраниални хеморагии:</strong> Хипоксията лесно причинява кръвоизливи в незрелия мозък.</li><li><strong>Бронхопулмонална дисплазия:</strong> Хронично увреждане на белия дроб при дълготрайна вентилация с високи концентрации на кислород.</li></ol><h4>Диагностичен маркер</h4><p><strong>Рентгенография на гръден кош:</strong> Наблюдава се картина тип <strong>\"матово стъкло\"</strong> (дифузно петнисто засенчване) и наличие на <strong>въздушна бронхограма</strong> (тъмните разклонения на бронхите се виждат ясно на фона на безвъздушния бял дроб).</p><h4>Изход. </h4><p>Той е неблагоприятен и през последните десетилетия, въпреки че се прилагат различни методи на контролирана вентилация и дори аерозолно приложение на сърфактант. По-добра е прогнозата, ако клиничното подобрение в резултат от приложеното адекватно лечение настъпи в първото  денонощие или до 48 h.</p><h2>2. Аспирационен синдром</h2><p>Това състояние представлява невъзпалителна пневмопатия, причинена от вдишване на различни материи (околоплодна течност, мекониум, кръв) преди, по време или веднага след раждането.</p><h3>Етиология и Патогенеза</h3><p>Основният механизъм е свързан с <strong>хипоксемията</strong>.</p><ul><li><strong>Механизъм:</strong> Когато плодът изпита хипоксия <em>in utero</em>, неговите нормални плитки респираторни движения се превръщат в дълбоки, гаспащи вдишвания. Това \"засмуква\" околоплодното съдържание в долните дихателни пътища.</li><li><strong>Специфика на мекониума:</strong> Хипоксията стимулира перисталтиката и отпуска аналния сфинктер на плода, при което се отделя мекониум в околоплодната течност. Неговата аспирация е най-опасна, тъй като той действа като механичен запушалка и химичен дразнител.</li></ul><h3>Патоморфологична картина</h3><h4>Макроскопски</h4><ul><li><strong>Бели дробове:</strong> Изглеждат обемни и „пъстри“. Наблюдава се мозаечна картина — тъмновиолетови зони на колапс (<strong>ателектаза</strong>) се редуват със светлорозови, раздути зони на <strong>емфизем</strong>.</li><li><strong>Дихателни пътища:</strong> В трахеята и главните бронхи често се открива вискозна слуз, примесена с кръв или зеленикав мекониум.</li><li><strong>Сърце:</strong> Поради високото съпротивление в белодробните съдове, често се наблюдава остра дилатация на дясната сърдечна камера.</li></ul><h4>Микроскопски</h4><p>В алвеолите и бронхиолите се установяват елементи на околоплодното съдържимо:</p><ul><li><strong>Епидермални клетки:</strong> Плоски вроговени клетки от кожата на плода.</li><li><strong>Лануго:</strong> Нежни пухести косъмчета.</li><li><strong>Мекониум:</strong> Вижда се като жълтеникаво-кафяви безструктурни маси или телца.</li><li><strong>Vernix caseosa:</strong> Мастни капки и детрит.</li><li><strong>Съдова реакция:</strong> Капилярите в стените на алвеолите са силно разширени и препълнени с кръв.</li></ul><h3>Клинични форми и усложнения</h3><p>Симптомите (тахипнея, цианоза, хлътване на гръдния кош) се проявяват <strong>веднага след раждането</strong>, което го отличава от ХМБ (където има „светъл период“).</p><p><strong>Основни усложнения:</strong></p><ol><li><strong>Пневмоторакс:</strong> Въздухът се задържа в алвеолите поради клапанния механизъм на запушване и може да пробие плеврата.</li><li><strong>Вторична пневмония:</strong> Аспирираният материал е идеална среда за развитие на бактерии (особено ако околоплодната течност е била инфектирана).</li><li><strong>Персистираща пулмонална хипертония:</strong> Трайно повишено налягане в белодробните съдове.</li></ol><h3>Прогноза</h3><ul><li><strong>Благоприятна:</strong> При плитка аспирация на чиста околоплодна течност, която се резорбира бързо.</li><li><strong>Сериозна/Фатална:</strong> При масивна аспирация на гъст <strong>мекониум</strong>, която води до тежка механична обструкция и химическо увреждане на белодробната тъкан.</li></ul><h2>3. Белодробна ателектаза (РДС тип II)</h2><p><strong>Синоними:</strong> Транзиторен РДС, ателектатична пневмопатия.</p><ul><li><strong>Етиология:</strong> Дължи се на <strong>забавена резорбция на феталната белодробна течност</strong>. Често се наблюдава при раждане с <strong>Цезарово сечение</strong>.</li><li><strong>Клинична картина:</strong> Дихателната недостатъчност се проявява <strong>веднага</strong> след раждането.</li><li><strong>Макроскопски:</strong> Белите дробове са малки (едва 1/3 от гръдната кухина), синкаво-червени с много остри предни ръбове.</li><li><strong>Микроскопски:</strong> Масивна ателектаза. <strong>Важно:</strong> Липсват хиалинни мембрани и аспирирани материи.</li><li><strong>Изход:</strong> Обикновено благоприятен; състоянието е транзиторно.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 108. Родова травма. Патогенеза, видове, характеристика.</h1><p>Родовата травма включва локални механични увреждания на плода, настъпили по време на раждането. Те са резултат от физически сили (притискане, разтягане), които водят до разкъсване на съдове и тъкани.</p><blockquote><strong>Разграничаване:</strong> Травмата трябва да се отличава от хипоксичното увреждане (<em>birth injury</em>). Травмата е механична, докато хипоксията е биохимична, въпреки че двете често се съчетават и утежняват прогнозата за новороденото.</blockquote><h3>Етиологични фактори и патогенеза</h3><p>Травмата е следствие от динамичното несъответствие между обема на плода и капацитета на родовия канал.</p><h4>1. Фактори от страна на плода и майката</h4><ul><li><strong>Макрозомия и хидроцефалия:</strong> Едрият плод или увеличената обиколка на главата изискват по-голяма изтласкваща сила, което увеличава триенето и натиска върху черепните кости.</li><li><strong>Анатомични пречки:</strong> Тесният таз, наличието на туморни процеси (миоми, костни екзостози) или ригидността на меките тъкани на майката концентрират механичното напрежение в специфични точки на плода.</li><li><strong>Недоносеност:</strong> Незрелите тъкани и съдове са изключително крехки; дори нормалните физиологични сили на раждането могат да се окажат травматични за недоносения плод.</li></ul><h4>2. Механизъм на силите</h4><p>Върху плода действат два вектора на напрежение:</p><ul><li><strong>Изтласкващ вектор:</strong> Генериран от маточните контракции и коремната преса.</li><li><strong>Реактивен вектор (съпротива):</strong> Силата на триене и натиск от костния таз.</li><li><strong>\"Вентузен ефект\":</strong> Когато предлежащата част (обикновено главата) се фиксира в родовия канал, се създава разлика в налягането. Интраутеринното налягане е високо, докато налягането под мястото на фиксация е атмосферно. Тази разлика \"засмуква\" течностите в меките тъкани, причинявайки стаза и оток.</li></ul><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fmindthebleep.com%2Fwp-content%2Fuploads%2F2024%2F11%2FNIPE-7-1.jpg&amp;f=1&amp;nofb=1&amp;ipt=d27e5a2581c57073669e120c25a8a0ee2c13001becc9d62d12ae6b1c299bde21 &quot;width=100%&quot;)\" id=\"note-1775939504128-0\">Основни повърхностни травми на главата</span></h3><h4>1. <span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fimage4.slideserve.com%2F232697%2Fcaput-succedaneum-l.jpg&amp;f=1&amp;nofb=1&amp;ipt=6b84781e83b228d8b7752983eb3d2daff85aebcc45bbf82a138225c54c10de8e &quot;width=100%&quot;)\" id=\"note-1775939532004-1\">Родова подутина</span> (Caput succedaneum)</h4><p>Това е серо-хеморагичен оток на меките тъкани, разположен в подкожието.</p><ul><li><strong>Локализация:</strong> Намира се <strong>над</strong> апоневрозата на скалпа.</li><li><strong>Характеристика:</strong> Мека, тестовата подутина с виолетов цвят. Понеже е повърхностна, тя <strong>не е ограничена от шевовете на костите</strong> и може да премине през тях.</li><li><strong>Изход:</strong> Резорбира се бързо – обикновено изчезва напълно до 48 часа.</li></ul><h4>2. <span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fi.ytimg.com%2Fvi%2FTyW41EQRAg0%2Fmaxresdefault.jpg%3Fsqp%3D-oaymwEmCIAKENAF8quKqQMa8AEB-AH-CYAC0AWKAgwIABABGBEgaChyMA8%3D%26rs%3DAOn4CLB44x77jCVnzof6CaeEEWqGatrWhQ&amp;f=1&amp;nofb=1&amp;ipt=d2bc6fb6ccdb10b11a2ebda5f26cd66c0fb4ed106f5f8b52204f841bcb847494 &quot;width=100%&quot;)\" id=\"note-1775939637304-2\">Кефалхематом</span> (Cephalhaematoma)</h4><p>Представлява кръвоизлив под периоста (надкостницата) на някоя от черепните кости.</p><ul><li><strong>Локализация:</strong> Най-често върху теменните кости. Тъй като периостът е здраво заловен за краищата на костите, този хематом <strong>никога не преминава черепните шевове</strong>.</li><li><strong>Клинична проява:</strong> Подутината е еластична и напрегната. Среща се при около 6% от новородените, по-често при момчета.</li></ul><h3>Усложнения и последствия</h3><p>Макар и локални, тези травми могат да доведат до системни проблеми:</p><ul><li><strong>Анемия и жълтеница:</strong> При масивни кефалхематоми (до 150 мл кръв) се развива анемия, а разпадът на кръвта води до повишен билирубин (жълтеница).</li><li><strong>Инфекции:</strong> Рядко хематомът може да нагное, което крие риск от менингит или увреждане на костта.</li><li><strong>Осификация:</strong> Ако резорбцията се забави, под надкостницата може да се образува нова кост, оставяйки трайна подутина.</li><li><strong>Вътрешен кефалхематом:</strong> Придружава се от фрактура на костта и събиране на кръв от вътрешната страна на черепа (епидурално), което е спешно състояние.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 109. Хемолитична болест на новороденото – еритробластоза. Форми, морфологична характеристика.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Синоним:</strong> Фетална еритробластоза.</p><p>ХБПН е имунологично заболяване, при което майчини антитела преминават през плацентата и атакуват еритроцитите на плода, водейки до тяхната хемолиза.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Етиология и Патогенеза</h3><ul><li><strong>Причина:</strong> Имунологичен конфликт между антигените на плода и антителата на майката.</li><ul><li><strong>Rh-система:</strong> Най-често (90% от случаите) при Rh (-) майка и Rh (+) плод (фактор D).</li><li><strong>AB0-система:</strong> По-рядко и обикновено протича по-леко.</li></ul><li><strong>Механизъм:</strong></li><ol><li>Фетални еритроцити проникват в майчиното кръвообращение (изоимунизация).</li><li>Майката произвежда антитела, които преминават обратно в плода.</li><li>Антителата блокират и хемолизират феталните еритроцити.</li><li>Резултат: <strong>Масивна анемия</strong> и <strong>Хипербилирубинемия</strong>.</li></ol></ul><h3>Морфологични изменения</h3><p>В отговор на хемолизата, организъм на плода развива:</p><ul><li><strong>Екстрамедуларна хемопоеза:</strong> Тъй като костният мозък не успява да компенсира загубата, черният дроб и слезката започват да произвеждат кръвни клетки.</li><li><strong>Еритробластоза:</strong> Поява на еритробласти в периферната кръв.</li><li><strong>Хепатоспленомегалия:</strong> Увеличение на черния дроб и слезката.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Основни клинико-морфологични форми</h3><p>Заболяването се разделя на четири форми според тежестта и времето на настъпване на имунологичния конфликт:</p><h4>Вътреутробна смърт с мацерация (Fetus mortus maceratus)</h4><ul><li><strong>Етиология:</strong> Дължи се на ранно и масивно проникване на антитела (20-24 г.с.), когато плодът е незрял и функционално нерезистентен. Развиват се бързи и тежки алтеративни промени.</li><li><strong>Макроскопски:</strong> Напреднала <strong>мацерация </strong>(размекване и излющване на кожата) и <strong>автолитични </strong>промени на вътрешните органи, съпроводени с хепато-спленомегалия.</li><li><strong>Микроскопски:</strong> Тъй като изследването е затруднено от автолизата, се търсят по-резистентни органи (бял дроб, бъбреци) или запазени участъци от черен дроб и слезка. Наблюдават се:</li><ul><li><strong>Еритробласти и нормобласти</strong> в кръвоносните съдове.</li><li><strong>Хемосидерин</strong> в клетките на моноцитомакрофагиалната система (доказва се чрез оцветяване по Перлс).</li></ul></ul><h4>Оточна форма (Hydrops foetus universalis)</h4><ul><li><strong>Патогенеза:</strong> Развива се при продължително въздействие на умерено количество антитела върху незрял плод. Характеризира се с усилена екстрамедуларна хемопоеза (еритробластоза).</li><li><strong>Промени:</strong> Хепатоспленомегалия, хиперплазия на лимфните органи, изменения в сърцето и ендокринните жлези, увреждане на съдовете (оток и кръвоизливи). Живородените са нежизнеспособни.</li><li><strong>Макроскопски:</strong></li><ul><li>Новороденото е <strong>силно оточно </strong>(телесната маса може да е двойно по-голяма).</li><li>Кожа: Подпухнала, бледа, иктерична и пастьозна.</li><li>Телесните кухини съдържат обилно количество <strong>прозрачна сламеножълта течност</strong>.</li></ul></ul><h4>Иктерична форма (Icterus foetus gravis)</h4><ul><li><strong>Патогенеза:</strong> Развива се в зрял плод при преминаване на антитела в късните срокове или по време на раждането. Водещ фактор е интоксикацията с <strong>индиректен билирубин</strong> поради масивна хемолиза.</li><li><strong>Клинична картина:</strong> Плодът се ражда жизнеспособен, без отоци; жълтеницата е налице при раждането или се появява до 2-3 дни.</li><li><strong>Морфология при аутопсия:</strong></li><ul><li><strong>Кожа и органи:</strong> Интензивно жълто оцветяване.</li><li><strong>Слезка:</strong> Увеличена 2-3 пъти.</li></ul><li><strong>Късни прояви:</strong> <strong>Билирубинова енцефалопатия</strong>, водеща до изоставане в психическото развитие, двигателни нарушения, глухота, атетоза и гърчове.</li><li><strong>Изход:</strong>&nbsp;<p>Смъртта настъпва от <strong>билирубиновата ен</strong></p><p><strong>цефалопатия</strong>; от <strong>инфекциозни усложнения </strong>- пнев</p><p>мония; сепсис и от усложнения, </p><p>свързани с лечението.</p></li></ul><h3>Анемична форма (от лекция)</h3><ul><li><p><strong>Лека хемолиза</strong>: </p><p>Активира се екстрамедуларната хемопоеза → нивата на Er се запазват в норма.</p><br></li><li><p><strong>Тежка хемолиза</strong>: </p><p>Води до прогресивна анемия → развива се хипоксия на сърцето и черния дроб.</p><br></li><ul><li><strong>Чернодробен дефицит и сърдечна недостатъчност</strong>: Намаленият синтез на плазмени протеини (2–2.5 mg/dl) води до понижаване на онкотичното налягане, а сърдечната декомпенсация повишава хидростатичното налягане → в резултат се развива генерализиран оток (анасарка) → hydrops fetalis.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Профилактика и изход</h3><ul><li><strong>Профилактика:</strong> Третиране на Rh (-) бременни жени с <strong>Rh-имуноглобулин</strong>, което е свалило смъртността под 2%.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 110. Инфекциозни заболявания на новороденото. Фетален вирусен хепатит. Рубеола. Листериоза.</h1><h2><strong style=\"color: rgb(88, 129, 87)\">Неонатален (фетален) хепатит</strong></h2><p>Неонаталният хепатит е неспецифичен термин за <strong>интрахепатална</strong> <strong>холестаза </strong>от различни причини. Проявява се като продължителна конюгирана хипербилирубинемия при новороденото (неонатална холестаза), с честота около 1:2500 живородени.</p><ul><li><strong>Етиология:</strong></li><ul><li><strong>Идиопатичен неонатален хепатит (50%)</strong> – най-честата диагноза при липса на друга открита причина.</li><li><strong>Билиарна атрезия (20%)</strong> – често се припокрива клинично с идиопатичния хепатит.</li><li><strong>Дефицит на α1<span class=\"vlist\" style=\"height: 0.3011em\"></span>​<span class=\"vlist\" style=\"height: 0.15em\"></span>-антитрипсин (15%)</strong>.</li><li>Прекаран вътреутробно вирусен хепатит (тип А или В).</li></ul><li><strong>Морфология:</strong></li><ul><li>Нарушена архитектоника с фокална апоптоза и некроза на хепатоцити, съчетани с <strong>гигантоклетъчна трансформация </strong>(многоядрени хепатоцити) като израз на регенераторна компенсаторна реакция.</li><li>Хепатоцелуларна и каналикуларна холестаза – наличие на <strong>жлъчни цилиндри</strong>, а при локализация в синусоидите – <strong>жлъчни тромби</strong>.</li><li>Лека мононуклеарна инфилтрация в порталните пространства, с реактивни промени в Купферовите клетки.</li><li>Наличие на екстрамедуларна хемопоеза в черния дроб.</li></ul></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3><strong>РУБЕОЛА (Синдром на Gregg)</strong></h3><p>Рубеолата е най-важната инфекциозна причина за вродени пороци. При заразяване в първите 2 седмици от бременността, рискът за ембриона е <strong>100%</strong>.</p><h3><strong>Рубеолна ембриопатия</strong></h3><p>Развива се при инфекция до <strong>16-а г.с.</strong> (критично до 8-а г.с.). Вирусът атакува тъкани с <strong>ектодермален произход</strong>.</p><ul><li><strong>Класическа триада на Gregg:</strong></li><ol><li><strong>Очно засягане:</strong> <strong>Катаракта</strong>, микрофталмия, потъмняване на стъкловидното тяло и <strong>глаукома</strong> (поради пороци в дренажната система на окото).</li><li><strong>Сърдечно-съдови пороци:</strong> Дефекти на предсърдната и камерната преграда (<strong>50-90%</strong>), <strong>Тетралогия на Фало</strong>, стеноза на аортната и пулмоналната клапа, коарктция на аортата и незатваряне на артериалния проток.</li><li><strong>Слух:</strong> Глухота поради аномалии във формирането на вътрешното, средното и външното ухо.</li></ol><li><strong>ЦНС:</strong> Микроцефалия, хипоплазия на мозъчни дялове и <strong>забавено умствено развитие</strong>.</li><li><strong>Други:</strong> Описани са хипоплазия на бъбреците и панкреаса, както и нарушения в зъбния зародиш.</li></ul><p><strong>Изход</strong>: Бременността често завършва с аборт, вътреутробна смърт или симетрична вътреутробна хипоплазия с или без смущения в съзряването.</p><h3><strong>Рубеолна фетопатия</strong></h3><p>Развива се в по-късните етапи или като продължение на ембриопатията. Тук процесът е възпалително-деструктивен.</p><ul><li><strong>Клинични белези:</strong> Недоносеност (<strong>тегло &lt; 2500 гр.</strong>), цианотична и суха кожа с характерен <strong>хеморагичен обрив</strong>.</li><li><strong>Специфична морфология по системи:</strong></li><ul><li><strong>Черен дроб:</strong> Увеличен, с огнищни <strong>некрози</strong>, засилена <strong>екстрамедуларна хемопоеза</strong> и инфилтрати от кръгли клетки между делчетата.</li><li><strong>Главен мозък:</strong> Дисеминирана ангиоматоза (разрастване на съдове) и <strong>некротичен енцефалит</strong>. Характерни са <strong>калцификати </strong>и формирането на глиални цикатрикси или псевдокисти.</li><ul><li><p><strong>Диференциална диагноза:</strong> При наличие на мозъчни калцификати и некрози, рубеолата трябва да се разграничи от <strong>токсоплазмоза</strong> чрез серологично изследване.</p><br></li></ul><li><strong>Бели дробове:</strong> Картина на <strong>интерстициална вирусна пневмония</strong> с наличие на гигантски клетки; по-късно води до пневмосклероза.</li><li><strong>Сърдечно-съдова система:</strong> Мукоидно и фибриноидно набъбване на малките артерии с ендотелна пролиферация .</li></ul></ul><p><strong>Изход:  </strong>Зависи от тежестта на множествените малформации. Преживелите деца често развиват <strong>диабет</strong> (поради тежък фиброзен панкреатит), имат отклонения в имунитета и са силно податливи на вторични инфекции.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><strong>ЛИСТЕРИОЗА (Listeriosis)</strong></h2><p>Листериозата е типична перинатална инфекция с тежки последици за плода и новороденото.</p><ul><li><strong>Причинител:</strong> <em>Listeria monocytogenes</em> – Gram (+) подвижен, факултативен интрацелуларен бактерий.</li><li><strong>Източник:</strong> Замърсени хранителни продукти.</li><li><strong>Клинична картина при бременни:</strong> Протича леко (грипоподобно) с възможен цистит или пиелонефрит, но за плода е фатална – води до <strong>аборт, преждевременно раждане или мъртвораждане</strong>.</li></ul><h4><strong>Морфологични форми при плода и новороденото</strong></h4><p>Според механизма на заразяване се различават две форми:</p><ol><li><strong>Генерализирана</strong> (хематогенно-диаплацентарно заразяване).</li><li><strong>Локална</strong> (чрез аспирация или поглъщане на заразена околоплодна течност).</li></ol><h4><strong>А. Генерализирана септична форма (<em>Granulomatosis infanti septica</em>)</strong></h4><p>Това е най-тежкото протичане със смъртност до <strong>80%</strong> в рамките на 3-4 дни.</p><ul><li><strong>Клиника:</strong> Треска, повръщане, диария, цианоза, иктер, сънливост и гърчове.</li><li><strong>Макроскопска находка:</strong> Характеризира се с дисеминирани <strong>милиарни грануломи</strong> в почти всички органи:</li><ul><li><strong>Органи:</strong> Черен дроб, слезка, бели дробове, лимфни възли, костен мозък, сърце, бъбреци, надбъбреци и мускули.</li><li><strong>Описание:</strong> Грануломите са с големина до няколко мм, кръгли, сиво-жълтеникави. Разположени са на оточен, хиперемиран или хеморагичен фон.</li><li><strong>Локализация:</strong> В главния мозък са по хода на съдовете; в храносмилателния тракт са по лигавиците или подлигавично.</li></ul><li><strong>Микроскопска находка:</strong></li><ul><li><p>В органите се установяват огнища на начална <strong>некроза</strong>, които могат да прогресират до обширни некротични фокуси, с оформяне на клетъчен вал от <strong>хистиоцити, епителоидни клетки и моноцити</strong>.</p></li><li><p>Наблюдава се <strong>г</strong><strong>нойно-некротично възпаление</strong>, като в мозъка в периферията на грануломите участват левкоцити и глиални клетки.</p><br></li><li><p><strong>Специфични промени по органи</strong>:</p><br></li><ul><li><p>Кожа – продуктивен <strong>васкулит</strong> в дермата.</p></li><li><p>Бели дробове – гнойно-некротична перифокална пневмония и <strong>тромбангит</strong>, с перибронхиално и субплеврално разположени грануломи.</p></li><li><p>Мозък – чести <strong>тромбваскулитни промени</strong>.</p></li><li><p>Костен мозък и лимфни възли – <strong>милиарни некрози</strong>.</p></li></ul><li><p>В некротичните огнища се откриват <strong>Gram (+) къси пръчици</strong> (сини при H&amp;E), обикновено заобиколени от <strong>неутрофили</strong>.</p></li></ul></ul><h4><strong>Б. Локализирана форма</strong></h4><p>Морфологичните промени са идентични с генерализираната форма, но са ограничени според мястото на заразяване. Клиничната картина протича по-леко като <strong>пневмония</strong>, <strong>менингит </strong>или <strong>ентерит</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 111. Инфекциозни заболявания на новороденото. Пневмонии. Сепсис на новороденото.</h1><h1><strong style=\"color: rgb(88, 129, 87)\">Пневмонии на новороденото</strong></h1><p>Пневмониите са водеща причина за смъртност (до 3% от всички новородени), поради незрялост на паренхима и имунната система. При новородените те често протичат <strong>генерализирано</strong>, водейки до септицемия с преобладаващи некротични процеси.</p><h4><strong>Основни характеристики:</strong></h4><ul><li><strong>Етиология:</strong> Най-често Gr(-) бактерии (<em>E. coli</em>, <em>Klebsiella</em>, <em>Pseudomonas aeruginosa</em>, <em>Proteus</em>), стафилококи, стрептококи и вируси (Респираторно-синцитиален вирус).</li><li><strong>Патогенеза:</strong> Инфекцията може да бъде антенатална (коннатална), интра- или постнатална. Предразполагащи фактори са незрялост, аспирация на околоплодни води, родова травма и асфиксия.</li><li><strong>Морфологични особености:</strong></li><ol><li>Имат <strong>дифузен характер</strong> (поради незрялост).</li><li>Наличие на <strong>диапедезни кръвоизливи</strong> и отоци (поради съдова незрялост).</li><li>Масивни ателектази поради дифузно увреждане на сърфактанта.</li></ol></ul><h3><strong>Клинично-морфологични форми</strong></h3><h4><strong>1. Вирусни пневмонии</strong></h4><ul><li><strong>Макроскопски:</strong> Белите дробове са с хиперемия и ателектатични зони.</li><li><strong>Микроскопски:</strong> Картината не се отличава от тази при възрастни (интерстициален характер). Ценен диагностичен метод е флуорисцентното изследване със специфични антитела срещу вирусните антигени. Най-чест е респираторно-синцитиалният вирус при аспирация.</li></ul><h4><strong>2. Бактериални пневмонии</strong></h4><ul><li><strong>Pseudomonas aeruginosa (Ps. aeruginosa):</strong> Честа при недоносени. Характеризира се със силно деструктивно действие.</li><ul><li><strong>Макроскопски:</strong> Субплеврални сивкаво-белезникави некротични огнища без хиперемичен вал.</li><li><strong>Микроскопски:</strong> Коагулационен тип некроза със слаба или липсваща възпалителна реакция, тромбози и кръвоизливи.</li></ul><li><strong>Стрептококови пневмонии:</strong></li><ul><li>През първото денонощие са трудно отличими от ХМБ (Хиалинно-мембранна болест).</li><li><strong>Микроскопски:</strong> Венозен застой, оток, ателектази и <strong>хиалинни мембрани</strong> (съставени от детрит, некротични алвеолоцити и малко фибрин).</li></ul><li><strong>Стафилококови пневмонии:</strong></li><ul><li><strong>Макроскопски:</strong> Деструктивен характер с образуване на групирани <strong>\"гроздовидни\" абсцеси</strong> по хода на бронхите. Могат да формират големи кухини (<strong>пневматоцеле</strong>).</li><li><strong>Усложнения:</strong> Пневмоторакс, фибринозен или гноен плеврит.</li></ul></ul><h4><strong>Пневмоцистна пневмония (Pneumocystis carinii/jirovecii)</strong></h4><p>Среща се предимно при недоносени и деца с понижен имунитет.</p><ul><li><strong>Макроскопски:</strong> Белите дробове са <strong>дифузно плътни, розово-оранжеви</strong> на цвят.</li><li><strong>Микроскопски:</strong> Алвеолите са изпълнени с пенест ексудат (\"пчелна пита\").</li><li><strong>Доказване:</strong> Причинителят се доказва чрез специално <strong>оцветяване по Грокот</strong>, при което пневмоцистите се оцветяват в <strong>зелено-черен цвят</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h1>Сепсис у новородени и деца</h1><h2><strong style=\"color: rgb(88, 129, 87)\">Обща характеристика и честота</strong></h2><ul><li><strong>Патофизиология</strong>: Идентична с тази при възрастните, но се отличава съществено по етиологични фактори, имунен отговор и лечение.</li><li><strong>Честота</strong>: Варира от <strong>1 до 8 на 1000 живородени</strong>.</li><li><strong>Риск и гестационна възраст</strong>: Рискът нараства пропорционално с недоносеността – от 0.6% при доносени деца до <strong>16.6%</strong> при родени в 28 г.с..</li></ul><h2><strong style=\"color: rgb(88, 129, 87)\">Класификация според времето на поява</strong></h2><p><strong style=\"color: rgb(88, 129, 87)\">1. Сепсис с ранна поява (до 72 часа от раждането)</strong></p><ul><li><strong>Рискови фактори:</strong> Липса на перинатални грижи, пролонгирано раждане (&gt;18 часа), хориоамнионит, бактериална вагиноза.</li><li><strong>Критичен фактор:</strong> Майчино носителство на <strong>стрептококи група В</strong>.</li><li><strong>Механизъм:</strong> Заразяване чрез асцендиране на инфекцията от матката или при преминаване през вагината.</li><li><strong>Етиология:</strong> Доминират <strong>Грам (+) организми (57%)</strong>, главно стрептококи. По-рядко Листерия и ентерококи. От Грам (-) най-чести са <em>E. coli</em>, <em>Proteus</em> и <em>Haemophilus influenzae</em>.</li><li><strong>Клинична изява:</strong> Често се проявява като <strong>пневмония (35–55%)</strong> или менингит (5–15%).</li></ul><h3><strong>2. Сепсис с късна поява (след 3-ия ден)</strong></h3><ul><li><strong>Рискови фактори:</strong> Продължителна хоспитализация (вътреболнични инфекции), използване на венозни катетри за продължителен достъп.</li><li><strong>Честота:</strong> До 25% от недоносените в интензивни отделения развиват тази форма.</li><li><strong>Етиология:</strong> <p>Преобладават <strong>нозокомиални </strong>(вътреболнични) <strong>инфекции </strong></p>- главно&nbsp;<strong>коагулаза-негативни стафилококи</strong> (<em>S. epidermidis</em>). Чести Грам (-) са <em>Klebsiella</em>, <em>E. coli</em>, микози (<em>Candida</em>) и вируси (Herpes-simplex, RSV).</li></ul><h3><strong>3. Сепсис при по-големи деца</strong></h3><ul><li><strong>Основни причинители:</strong> <em>Str. pneumoniae</em> (най-висока бактериемия), <em>Neisseria meningitidis</em>, <em>St. aureus</em>, <em>Salmonella</em>.</li><li><strong>Менингокок:</strong> Най-смъртоносен (15–30% развиват <strong>фулминантен сепсис</strong>).</li><li><strong>β-хемолитичен стрептокок група А:</strong> Предизвиква некротизиращ фасциит и септичен шок.</li></ul><h2><strong>Патогенеза и Имунен статус</strong></h2><p>Централният фактор е <strong>относителното имунодефицитно състояние</strong> на новороденото:</p><ul><li><strong>Хуморален имунитет:</strong> Нивата на <strong>IgM и IgA</strong> са едва <strong>1–10%</strong> от тези при възрастни. Майчините <strong>IgG</strong> не преминават плацентата преди 32-ра г.с.</li><li><strong>Система на комплемента:</strong> Активността е 50% от тази на майката. При недоносени (28 г.с.) е само 20–60%. Това нарушава неутрофилната фагоцитоза.</li><li><strong>Клетъчен имунитет:</strong></li><ul><li>Неутрофилите имат ограничена възможност за нарастване при инфекция.</li><li>Несъвършенства в <strong>миграцията, хемотаксиса и опсонизацията</strong>.</li><li>Т-лимфоцитите имат намалена хелперна и повишена супресорна активност.</li></ul></ul><h3><strong>Бактериална вирулентност:</strong></h3><ul><li><strong>E. coli:</strong> Притежават адхезини и антигени <strong>О и К</strong>, които увеличават вирулентността им.</li><li><strong>S. epidermidis:</strong> Продуцира <strong>гликокаликс</strong>, който протектира бактериите от антибиотици.</li></ul><h2><strong>Специфични форми и входни врати</strong></h2><p>При търсене на източника на сепсис винаги се изследват потенциалните огнища: кожа, бели дробове, черва, средно ухо, пикочни пътища, слюнчени жлези.</p><ul><li><strong>Омфалогенен сепсис:</strong></li><ul><li>Характерно е, че <strong>входната врата (пъпната връв) съвпада със септичното огнище</strong>.</li><li>Хистологично: Възпалителни промени в стените на пъпните съдове.</li><li>Задължително изследване при деца до 1 година със септично състояние.</li></ul><li><strong>Криптогенен сепсис:</strong> Когато входната врата не може да бъде открита</li></ul><p><br></p><br><br><br><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
